L["Use class and reaction colors on "] = "Utiliser les couleurs de classe et réaction sur "
L["Use class and reaction colors on party health bars. Turn this off to keep them flat health green."] = "Utiliser les couleurs de classe et de réaction sur les barres de santé de groupe. Désactivez pour les garder en vert santé uniforme."
L["Use Class Colors"] = "Utiliser les couleurs de classe"
